@@ -1820,6 +1820,55 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
     return nullptr;

   FCmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
+
+  // If both comparisons have the same ordered predicate and the same LHS:
+  // (fcmp olt X, C1) | (fcmp olt X, C2) --> fcmp olt X, max(C1, C2)
+  // (fcmp ogt X, C1) | (fcmp ogt X, C2) --> fcmp ogt X, min(C1, C2)
+  // (fcmp olt X, C1) & (fcmp olt X, C2) --> fcmp olt X, min(C1, C2)
+  // (fcmp ogt X, C1) & (fcmp ogt X, C2) --> fcmp ogt X, max(C1, C2)
+  // This also works for OLE/OGE predicates.
+  // Similarly for ULT/UGT/ULE/UGE.
+  if (LHS0 == RHS0 && PredL == PredR) {
+    const APFloat *C1, *C2;
+    if (match(LHS1, m_APFloat(C1)) && match(RHS1, m_APFloat(C2))) {
+      auto IsLessThanPred = [](FCmpInst::Predicate P) {
+        return P == FCmpInst::FCMP_OLT || P == FCmpInst::FCMP_OLE ||
+               P == FCmpInst::FCMP_ULT || P == FCmpInst::FCMP_ULE;
+      };
+      auto IsGreaterThanPred = [](FCmpInst::Predicate P) {
+        return P == FCmpInst::FCMP_OGT || P == FCmpInst::FCMP_OGE ||
+               P == FCmpInst::FCMP_UGT || P == FCmpInst::FCMP_UGE;
+      };
+      // For less-than predicates:
+      // - OR: return the comparison with the larger constant (weaker condition)
+      //   If X < C1 and C1 < C2, then X < C1 implies X < C2
+      //   So (X < C1) | (X < C2) = X < C2
+      // - AND: return the comparison with the smaller constant (stronger condition)
+      //   If X < C1 and C1 < C2, then X < C1 implies X < C2
+      //   So (X < C1) & (X < C2) = X < C1
+      // For greater-than predicates, the logic is reversed:
+      // - OR: return the comparison with the smaller constant (weaker condition)
+      // - AND: return the comparison with the larger constant (stronger condition)
+      if (IsLessThanPred(PredL)) {
+        if (C1->compare(*C2) == APFloat::cmpLessThan) {
+          // C1 < C2
+          return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+        } else if (C1->compare(*C2) == APFloat::cmpGreaterThan) {
+          // C1 > C2
+          return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+        }
+      } else if (IsGreaterThanPred(PredL)) {
+        if (C1->compare(*C2) == APFloat::cmpGreaterThan) {
+          // C1 > C2
+          return IsAnd ? static_cast<Value *>(LHS) : static_cast<Value *>(RHS);
+        } else if (C1->compare(*C2) == APFloat::cmpLessThan) {
+          // C1 < C2
+          return IsAnd ? static_cast<Value *>(RHS) : static_cast<Value *>(LHS);
+        }
+      }
+    }
+  }
