static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                                   FCmpInst *RHS, bool IsAnd) {
  Value *LHS0 = LHS->getOperand(0), *LHS1 = LHS->getOperand(1);
  Value *RHS0 = RHS->getOperand(0), *RHS1 = RHS->getOperand(1);
  if (LHS0->getType() != RHS0->getType())
    return nullptr;

  FCmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();

  // If both comparisons have the same ordered predicate and the same LHS:
  // (fcmp olt X, C1) | (fcmp olt X, C2) --> fcmp olt X, max(C1, C2)
  // (fcmp ogt X, C1) | (fcmp ogt X, C2) --> fcmp ogt X, min(C1, C2)
  // (fcmp olt X, C1) & (fcmp olt X, C2) --> fcmp olt X, min(C1, C2)
  // (fcmp ogt X, C1) & (fcmp ogt X, C2) --> fcmp ogt X, max(C1, C2)
  // This also works for OLE/OGE predicates.
  // Similarly for ULT/UGT/ULE/UGE.
  if (LHS0 == RHS0 && PredL == PredR) {
    const APFloat *C1, *C2;
    if (match(LHS1, m_APFloat(C1)) && match(RHS1, m_APFloat(C2))) {
      auto IsLessThanPred = [](FCmpInst::Predicate P) {
        return P == FCmpInst::FCMP_OLT || P == FCmpInst::FCMP_OLE ||
